module RefModule(  
    input wire clk,  
    input wire reset_n,  
    output reg reset_out  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt) begin  
        if (!reset_n)  
            reset_out <= 1'b1;  
        else  
            reset_out <= 1'b0;  
    end  
endmodule
